const d = $('Gather All Data').first().json;

let perfContext = '';
try {
  const perf = $('Get Performance').first().json;
  if (perf && perf.context_text) {
    perfContext = `\n\n## Track record context\n${perf.context_text}\nUse this to calibrate confidence. Do not repeat recently failed patterns.`;
  }
} catch(e) {}

const watchlist = ['GOLD', 'SILVER', 'WTI_OIL', 'NATGAS', 'COPPER', 'SPY', 'QQQ', 'BTC', 'ETH'];
const evidence = {
  regime: d.regime || null,
  seasonality_count: Array.isArray(d.seasonality) ? d.seasonality.length : 0,
  cot_count: Array.isArray(d.cot) ? d.cot.length : 0,
  geopolitics_count: Array.isArray(d.geopolitics) ? d.geopolitics.length : 0,
  macro_price_count: Array.isArray(d.macro_prices) ? d.macro_prices.length : 0,
  commodity_price_count: Array.isArray(d.commodity_prices) ? d.commodity_prices.length : 0,
};

const prompt = `Ты - риск-ориентированный макро/кросс-актив аналитик Mini-Aladdin. Это информационный бриф, не финансовая рекомендация. Отвечай только валидным JSON на русском.${perfContext}

Цель: не пересказывать сырые данные, а решить, есть ли actionable setup. Если доказательств мало или конфликт факторов сильный - ставь HOLD или NO_TRADE, не выдумывай сделку.

## Evidence coverage
${JSON.stringify(evidence, null, 2)}

## Current macro regime
${JSON.stringify(d.regime, null, 2)}

## Seasonality
${JSON.stringify(d.seasonality, null, 2)}

## COT positioning
${JSON.stringify(d.cot, null, 2)}

## Geopolitical events
${JSON.stringify(d.geopolitics, null, 2)}

## Macro prices
${JSON.stringify(d.macro_prices, null, 2)}

## Commodity prices
${JSON.stringify(d.commodity_prices, null, 2)}

Верни JSON массив из 1-5 объектов только для лучших сетапов из [${watchlist.join(', ')}].
Схема:
[{
  "asset": "GOLD",
  "direction": "BUY|SELL|HOLD|NO_TRADE",
  "conviction": 1,
  "timeframe": "swing|position|long_term",
  "reasoning": "2-3 коротких факта, почему сейчас",
  "risk_note": "что отменяет идею",
  "action": "что делать: wait for pullback / monitor / no action / paper trade only",
  "evidence": ["regime", "cot", "seasonality"]
}]

Правила:
- BUY/SELL только при conviction >= 7 и минимум 2 независимых факторах.
- HOLD/NO_TRADE допустимы и полезны, если setup слабый.
- Не используй Markdown.
- Никакого текста вне JSON.`;

return [{ json: { prompt, watchlist, evidence, has_data: !!(d.regime || d.seasonality || d.commodity_prices) } }];

const resp = $input.first().json;
let text = '';
try {
  text = resp.candidates[0].content.parts[0].text || '';
} catch(e) {
  return [{ json: { error: 'No AI response', raw: JSON.stringify(resp).slice(0, 500) } }];
}

text = text.replace(/```json|```/g, '').trim();

let recommendations = [];
try {
  const jsonMatch = text.match(/\[\s*\{[\s\S]*\}\s*\]/);
  recommendations = JSON.parse(jsonMatch ? jsonMatch[0] : text);
} catch(e) {
  return [{ json: { error: 'Parse failed', raw: text.slice(0, 500) } }];
}

const allowedAssets = new Set(['GOLD', 'SILVER', 'WTI_OIL', 'NATGAS', 'COPPER', 'SPY', 'QQQ', 'BTC', 'ETH']);
const allowedDirections = new Set(['BUY', 'SELL', 'HOLD', 'NO_TRADE']);
const allowedTimeframes = new Set(['swing', 'position', 'long_term']);

const cleaned = recommendations
  .filter(r => r && allowedAssets.has(String(r.asset || '').toUpperCase()))
  .map(r => ({
    asset: String(r.asset).toUpperCase(),
    direction: allowedDirections.has(String(r.direction || '').toUpperCase()) ? String(r.direction).toUpperCase() : 'NO_TRADE',
    conviction: Math.max(1, Math.min(10, Number(r.conviction) || 1)),
    timeframe: allowedTimeframes.has(r.timeframe) ? r.timeframe : 'swing',
    factors: JSON.stringify({ evidence: Array.isArray(r.evidence) ? r.evidence.slice(0, 5) : [] }),
    reasoning: String(r.reasoning || '').trim(),
    risk_note: String(r.risk_note || '').trim(),
    action: String(r.action || '').trim(),
    valid_until: new Date(Date.now() + 24*60*60*1000).toISOString()
  }))
  .filter(r => r.reasoning && r.risk_note)
  .sort((a, b) => b.conviction - a.conviction)
  .slice(0, 5);

if (!cleaned.length) {
  return [{ json: {
    asset: 'NO_TRADE',
    direction: 'NO_TRADE',
    conviction: 1,
    timeframe: 'swing',
    factors: JSON.stringify({ evidence: [] }),
    reasoning: 'Модель не вернула валидных сетапов с достаточной доказательной базой.',
    risk_note: 'Не открывать новые позиции без ручной проверки графика и ликвидности.',
    action: 'No action today',
    valid_until: new Date(Date.now() + 24*60*60*1000).toISOString()
  } }];
}

return cleaned.map(r => ({ json: r }));

const items = $input.all();
const allData = $('Gather All Data').first().json;
const commodityPrices = allData.commodity_prices || [];
const macroPrices = allData.macro_prices || [];
const tfMap = { swing: 'дни', position: 'недели', long_term: 'месяцы' };
const stopMap = { GOLD: 3, SILVER: 4, WTI_OIL: 3, NATGAS: 5, COPPER: 3, SPY: 2, QQQ: 2, BTC: 5, ETH: 5 };

function priceFor(asset) {
  const cp = commodityPrices.find(c => c.symbol === asset);
  if (cp && cp.price !== undefined && cp.price !== null) return Number(cp.price);
  const mp = macroPrices.find(m => m.indicator === asset);
  if (mp && mp.value !== undefined && mp.value !== null) return Number(mp.value);
  return null;
}

function fmt(n) {
  if (n === null || Number.isNaN(n)) return 'n/a';
  if (Math.abs(n) >= 1000) return n.toFixed(0);
  if (Math.abs(n) >= 10) return n.toFixed(2);
  return n.toFixed(4);
}

const rows = items.map(i => i.json).sort((a, b) => (b.conviction || 0) - (a.conviction || 0)).slice(0, 5);
const lines = rows.map((r) => {
  const entry = priceFor(r.asset);
  const riskPct = stopMap[r.asset] || 3;
  let plan = 'План: наблюдать, без входа.';
  if ((r.direction === 'BUY' || r.direction === 'SELL') && entry) {
    const long = r.direction === 'BUY';
    const stop = long ? entry * (1 - riskPct / 100) : entry * (1 + riskPct / 100);
    const target = long ? entry * (1 + riskPct * 2 / 100) : entry * (1 - riskPct * 2 / 100);
    plan = `Entry/ref ${fmt(entry)} | SL ${fmt(stop)} | TP ${fmt(target)} | risk ${riskPct}%`;
  }
  return [
    `${r.direction === 'BUY' ? 'BUY' : r.direction === 'SELL' ? 'SELL' : 'NO TRADE'} ${r.asset} (${r.conviction}/10, ${tfMap[r.timeframe] || r.timeframe})`,
    `Почему: ${r.reasoning}`,
    `Действие: ${r.action || plan}`,
    `Риск: ${r.risk_note}`,
    plan
  ].join('\n');
}).join('\n\n');

const now = new Date();
const days = ['Воскресенье','Понедельник','Вторник','Среда','Четверг','Пятница','Суббота'];
const months = ['янв','фев','мар','апр','мая','июн','июл','авг','сен','окт','ноя','дек'];
const date = `${days[now.getDay()]}, ${now.getDate()} ${months[now.getMonth()]}`;
const msg = `Mini-Aladdin Daily Brief\n${date}\n\n${lines}\n\nИнформационный бриф, не финсовет. Перед сделкой: график, ликвидность, размер позиции.`;
return [{ json: { message: msg } }];

const items = $input.all();
const stopMap = { 'GOLD': 3, 'SILVER': 4, 'WTI_OIL': 3, 'NATGAS': 5, 'COPPER': 3, 'BRENT_OIL': 3, 'SPY': 2, 'QQQ': 2, 'BTC': 5, 'ETH': 5 };

return items.map(item => {
  const r = item.json;
  // Get entry price from the gathered data node
  const allData = $('Gather All Data').first().json;
  const commodityPrices = allData.commodity_prices || [];
  const macroPrices = allData.macro_prices || [];

  // Find current price for this asset
  let entry = null;
  const cp = commodityPrices.find(c => c.symbol === r.asset);
  if (cp) entry = cp.price;
  if (!entry) {
    const mp = macroPrices.find(m => m.indicator === r.asset);
    if (mp) entry = mp.value;
  }
  if (!entry) return { json: { skip: true } };

  const riskPct = stopMap[r.asset] || 3;
  const rewardPct = riskPct * 2;
  const dir = r.direction === 'BUY' ? 'long' : 'short';

  let target, stop;
  if (dir === 'long') {
    stop = entry * (1 - riskPct / 100);
    target = entry * (1 + rewardPct / 100);
  } else {
    stop = entry * (1 + riskPct / 100);
    target = entry * (1 - rewardPct / 100);
  }

  // Get regime
  const regime = allData.regime ? allData.regime.macro_regime : 'unknown';

  // valid_until based on timeframe
  const tfDays = { swing: 5, position: 14, long_term: 60 };
  const days = tfDays[r.timeframe] || 7;
  const validUntil = new Date(Date.now() + days * 24 * 60 * 60 * 1000).toISOString();

  return {
    json: {
      asset: r.asset,
      direction: dir,
      conviction: r.conviction,
      timeframe: r.timeframe,
      regime_at_signal: regime,
      reasoning: r.reasoning,
      risk_note: r.risk_note,
      entry_price: entry,
      target_price: Math.round(target * 1000000) / 1000000,
      stop_price: Math.round(stop * 1000000) / 1000000,
      risk_pct: riskPct,
      reward_pct: rewardPct,
      valid_until: validUntil
    }
  };
}).filter(i => !i.json.skip);

